/**
 * Responsive image variants for static/images.
 *
 * Emits downscaled webp copies of every raster image into static/images/_r/
 * (gitignored, regenerated by `predev`/`prebuild`) so components can attach a
 * `srcset` without committing hundreds of derivatives:
 *
 *   static/images/foo/bar.webp
 *     → static/images/_r/foo/bar-400.webp
 *     → static/images/_r/foo/bar-800.webp
 *     → static/images/_r/foo/bar-1600.webp
 *
 * Every raster image gets all three files (never upscaled — a small source
 * just yields a copy at its native width), so `buildSrcset()` in
 * $lib/utils/imageVariants.ts can construct URLs by convention with no
 * manifest. Incremental: a variant is regenerated only when the source is
 * newer. Run with --check to verify freshness without writing (unused today,
 * mirrors generate-reference-index.mjs).
 */
import { readdir, stat, mkdir } from 'node:fs/promises';
import { dirname, join, relative, extname } from 'node:path';
import { fileURLToPath } from 'node:url';
import sharp from 'sharp';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const IMAGES_DIR = join(root, 'static', 'images');
const OUT_DIR = join(IMAGES_DIR, '_r');
export const VARIANT_WIDTHS = [400, 800, 1600];

const RASTER_EXT = new Set(['.webp', '.jpg', '.jpeg', '.png', '.avif']);

async function* walk(dir) {
	for (const entry of await readdir(dir, { withFileTypes: true })) {
		const full = join(dir, entry.name);
		if (entry.isDirectory()) {
			if (full === OUT_DIR) continue; // never recurse into our own output
			yield* walk(full);
		} else {
			yield full;
		}
	}
}

const t0 = Date.now();
let generated = 0;
let skipped = 0;

for await (const file of walk(IMAGES_DIR)) {
	if (!RASTER_EXT.has(extname(file).toLowerCase())) continue;

	const rel = relative(IMAGES_DIR, file);
	const relNoExt = rel.slice(0, -extname(rel).length);
	const srcStat = await stat(file);

	for (const width of VARIANT_WIDTHS) {
		const outFile = join(OUT_DIR, `${relNoExt}-${width}.webp`);
		try {
			const outStat = await stat(outFile);
			if (outStat.mtimeMs >= srcStat.mtimeMs) {
				skipped++;
				continue;
			}
		} catch {
			// variant missing — generate it
		}
		await mkdir(dirname(outFile), { recursive: true });
		await sharp(file)
			.resize({ width, withoutEnlargement: true })
			.webp({ quality: 80 })
			.toFile(outFile);
		generated++;
	}
}

console.log(`image variants: ${generated} generated, ${skipped} up to date (${Date.now() - t0}ms)`);
